import numpy as np

class EnsembleClassifier:
    def __init__(self, classifiers):
        self.classifiers = classifiers

    def predict(self, image):
        predictions = []
        accuracies = []

        for classifier in self.classifiers:
            prediction, accuracy = classifier.predict(image)
            predictions.append(prediction)
            accuracies.append(accuracy)

        return self.ensemble_prediction(predictions, accuracies)

    def ensemble_prediction(self, predictions, accuracies):
        unique_predictions, counts = np.unique(predictions, return_counts=True)
        weighted_counts = np.zeros_like(counts, dtype=float)

        for i, prediction in enumerate(unique_predictions):
            for j, pred in enumerate(predictions):
                if pred == prediction:
                    weighted_counts[i] += accuracies[j]

        max_index = np.argmax(weighted_counts)
        final_prediction = unique_predictions[max_index]
        confidence_level = weighted_counts[max_index] / np.sum(weighted_counts)

        return final_prediction, confidence_level

